INSERT INTO admin_action_log (
    actor_user_id, target_user_id, action_type, target_type,
    before_value, after_value, reason, ip_address, user_agent
)
VALUES (
    #{actorUserId}, #{targetUserId}, #{actionType}, #{targetType},
    CAST(COALESCE(#{beforeValue}, 'null') AS JSON),
    CAST(COALESCE(#{afterValue}, 'null') AS JSON),
    #{reason}, #{ipAddress}, #{userAgent}
)

mapper.select:
SELECT l.id, l.actor_user_id, actor.email AS actor_email, l.target_user_id, target.email AS target_email, l.action_type, l.target_type, JSON_UNQUOTE(JSON_EXTRACT(l.before_value, '$')) AS before_value, JSON_UNQUOTE(JSON_EXTRACT(l.after_value, '$')) AS after_value, l.reason, l.ip_address, l.user_agent, l.created_at FROM admin_action_log l LEFT JOIN users actor ON actor.id = l.actor_user_id LEFT JOIN users target ON target.id = l.target_user_id WHERE 1 = 1
AND ( actor.email LIKE CONCAT('%', #{keyword}, '%') OR target.email LIKE CONCAT('%', #{keyword}, '%') OR l.action_type LIKE CONCAT('%', #{keyword}, '%') OR l.reason LIKE CONCAT('%', #{keyword}, '%') )
AND l.action_type = #{actionType}
AND l.target_type = #{targetType}
ORDER BY l.created_at DESC, l.id DESC LIMIT #{limit}
